// Internal shared brand-glyph components used by the per-slug files in this
// directory. Each glyph returns a bare `<svg fill="currentColor">` WITHOUT a
// `data-slug` attribute — slug tagging is the per-slug wrapper's job (the test
// hook in `add-key-dialog.test.tsx` queries per-slug via `[data-slug=…]`).
//
// 2-tone discipline: every glyph below uses `fill="currentColor"` only. There
// are NO hex literals baked into these SVGs. The accent purple
// (`text-nyx-secondary-400`) is applied via Tailwind className on a wrapper
// `<span>` in the composite (per-slug) files, never inside the SVG itself.
//
// Sources:
//   - OpenAI, Anthropic, Mistral AI, DeepSeek, X (Twitter), Google, GitHub,
//     Facebook, Discord, Spotify, Slack, Microsoft, TikTok, Twitch, Reddit,
//     Telegram, AWS — path data hand-extracted from Simple Icons
//     (https://simpleicons.org, CC0 1.0). No runtime dependency on the
//     `simple-icons` npm package.
//   - Cohere, Lark, Feishu, OpenClaw — hand-built glyphs (these brands have no
//     Simple Icons entry and ship no publicly-extractable brand mark).

import type { ReactNode, SVGProps } from "react";

// Allow per-slug wrappers to set arbitrary `data-*` attributes (most importantly
// the `data-slug` test hook). React's intrinsic JSX elements accept `data-*`
// automatically, but a custom component like ours needs the explicit index
// signature to expose per-slug tagging through TS.
type GlyphProps = SVGProps<SVGSVGElement> & {
  [key: `data-${string}`]: string | number | boolean | undefined;
};

